mapper.select:
select r.id,r.name,r.course_id,r.teacher_id,r.update_time,r.position,
       r.type,r.picture,r.size,r.document_type,c.name as courseName,
       t.name as teacherName
    from resource r
    left join course c on c.id=r.course_id
    left join teacher t on t.teacher_id=r.teacher_id

    
        and r.id = #{id}
    
    
        and r.name like concat('%', #{name}, '%')
    
    
        and r.course_id = #{courseId}
    
    
        and c.name like concat('%', #{courseName}, '%')
    
    
        and r.type = #{type}
    
    and r.teacher_id = #{teacherId}

order by r.update_time desc

select r.id,r.name,r.course_id,r.teacher_id,r.update_time,r.position, r.type,r.picture,r.size,r.document_type,c.name as courseName, t.name as teacherName from resource r left join credit c2 on c2.course_id=r.course_id left join course c on c.id=r.course_id left join teacher t on t.teacher_id=r.teacher_id
and r.id = #{id}
and r.name like concat('%', #{name}, '%')
and r.course_id = #{courseId}
and c.name like concat('%', #{courseName}, '%')
and r.type = #{type}
and c2.student_id=#{studentId}
order by r.update_time desc
